import React, { useEffect, useState } from "react";
import { Link } from "react-router-dom";
import { Facebook, Instagram, Youtube, Github, ChevronLeft, ChevronRight, Star } from "lucide-react";

export default function Landing() {
  // State للآراء المتحركة
  const [currentSlide, setCurrentSlide] = useState(0);

  // بيانات الآراء
  const testimonials = [
    { id: 1, text: "أفضل مطعم في المدينة! طعم رائع وجودة عالية", name: "أحمد محمد" },
    { id: 2, text: "خدمة ممتازة وأجواء راقية. أنصح الجميع بتجربته", name: "سارة عبدالله" },
    { id: 3, text: "أكل لذيذ وأسعار مناسبة. سأعود مرة أخرى", name: "محمد علي" },
  ];

  // التحكم في السلايدر
  const nextSlide = () => {
    setCurrentSlide((prev) => (prev + 1) % testimonials.length);
  };

  const prevSlide = () => {
    setCurrentSlide((prev) => (prev - 1 + testimonials.length) % testimonials.length);
  };

  return (
    <div className="bg-black min-h-screen" dir="rtl">
      {/* ===================== النف بار (Navbar) ===================== */}
      {/* اللوجو على اليمين - الروابط على اليسار */}
      <nav className="fixed top-0 left-0 right-0 z-50 bg-black/90 backdrop-blur-md border-b border-green-500">
        <div className="container mx-auto px-4 py-4">
          <div className="flex items-center justify-between">
            {/* اللوجو على اليمين */}
            <div className="text-2xl font-bold text-green-500">
              مطعم<span className="text-white"> الذواقة</span>
            </div>

            {/* الروابط على اليسار */}
            <div className="hidden md:flex space-x-8 space-x-reverse">
              <a href="#" className="text-white hover:text-green-500 transition">الرئيسية</a>
              <a href="#" className="text-white hover:text-green-500 transition">القائمة</a>
              <a href="#" className="text-white hover:text-green-500 transition">عنا</a>
              <a href="#" className="text-white hover:text-green-500 transition">اتصل بنا</a>
            </div>
          </div>
        </div>
      </nav>

      {/* ===================== القسم الرئيسي (Hero) ===================== */}
      {/* النص الكلاسيكي على اليسار - صورة الطعام على اليمين */}
      <section className="pt-28 pb-16 bg-black">
        <div className="container mx-auto px-4">
          <div className="flex flex-col md:flex-row items-center gap-12">
            {/* النص الكلاسيكي على اليسار */}
            <div className="flex-1 text-right">
              <h1 className="text-4xl md:text-5xl font-bold text-white mb-4">
                أطيب <span className="text-green-500">المأكولات</span>
                <br />
                في أجواء <span className="text-green-500">رائعة</span>
              </h1>
              <p className="text-gray-400 text-lg leading-relaxed">
                نقدم لكم أشهى الأطباق التقليدية والعصرية 
                بأفضل المكونات الطازجة وجودة لا تضاهى.
              </p>
            </div>

            {/* صورة الطعام على اليمين */}
            <div className="flex-1">
              <img 
                src="https://images.unsplash.com/photo-1546069901-ba9599a7e63c?w=600&auto=format"
                alt="طعام شهي"
                className="rounded-lg w-full h-auto shadow-2xl border border-green-500"
              />
            </div>
          </div>
        </div>
      </section>

      {/* ===================== الآراء المتحركة (Carousel) ===================== */}
      <section className="py-16 bg-black">
        <div className="container mx-auto px-4">
          <h2 className="text-3xl font-bold text-center mb-12">
            <span className="text-green-500">آراء</span> عملائنا
          </h2>

          <div className="relative max-w-2xl mx-auto">
            <div className="overflow-hidden">
              <div 
                className="flex transition-transform duration-500"
                style={{ transform: `translateX(-${currentSlide * 100}%)` }}
              >
                {testimonials.map((item) => (
                  <div key={item.id} className="w-full flex-shrink-0 px-4">
                    <div className="bg-gray-900 rounded-2xl p-8 text-center border border-green-500">
                      <div className="flex justify-center mb-4">
                        {[...Array(5)].map((_, i) => (
                          <Star key={i} className="text-yellow-500 fill-current" size={20} />
                        ))}
                      </div>
                      <p className="text-white text-lg mb-4">"{item.text}"</p>
                      <p className="text-green-500 font-bold">{item.name}</p>
                    </div>
                  </div>
                ))}
              </div>
            </div>

            {/* أزرار التحكم */}
            <button 
              onClick={prevSlide}
              className="absolute top-1/2 -left-4 transform -translate-y-1/2 bg-green-600 hover:bg-green-700 rounded-full p-2 transition"
            >
              <ChevronLeft size={24} />
            </button>
            <button 
              onClick={nextSlide}
              className="absolute top-1/2 -right-4 transform -translate-y-1/2 bg-green-600 hover:bg-green-700 rounded-full p-2 transition"
            >
              <ChevronRight size={24} />
            </button>

            {/* نقاط المؤشر */}
            <div className="flex justify-center mt-6 gap-2">
              {testimonials.map((_, idx) => (
                <button
                  key={idx}
                  onClick={() => setCurrentSlide(idx)}
                  className={`w-2 h-2 rounded-full transition-all ${
                    currentSlide === idx ? 'w-6 bg-green-500' : 'bg-gray-600'
                  }`}
                />
              ))}
            </div>
          </div>
        </div>
      </section>

      {/* ===================== التذييل (Footer) ===================== */}
      {/* أيقونات فيسبوك، يوتيوب، انستغرام، قيت هوب */}
      <footer className="bg-black border-t border-green-500 py-8">
        <div className="container mx-auto px-4">
          <div className="flex justify-center gap-8 mb-4">
            <a href="#" className="text-gray-400 hover:text-green-500 transition transform hover:scale-110">
              <Facebook size={28} />
            </a>
            <a href="#" className="text-gray-400 hover:text-green-500 transition transform hover:scale-110">
              <Instagram size={28} />
            </a>
            <a href="#" className="text-gray-400 hover:text-green-500 transition transform hover:scale-110">
              <Youtube size={28} />
            </a>
            <a href="#" className="text-gray-400 hover:text-green-500 transition transform hover:scale-110">
              <Github size={28} />
            </a>
          </div>
          <p className="text-gray-500 text-sm text-center">
            © {new Date().getFullYear()} مطعم الذواقة. جميع الحقوق محفوظة
          </p>
        </div>
      </footer>
    </div>
  );
}
